import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * CELL_SIZE * 3  # Triple width for 3 players
SCREEN_HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
COLORS = [(0, 0, 0), (255, 0, 0), (0, 255, 0), (0, 0, 255),
          (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 255, 255)]  # Add white

# Tetromino shapes (7 standard shapes)
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]  # 0 represents empty cell

    def is_valid_move(self, shape, x, y):
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    grid_x = x + j
                    grid_y = y + i
                    if (grid_x < 0 or grid_x >= self.width or
                            grid_y < 0 or grid_y >= self.height or
                            self.grid[grid_y][grid_x] != 0):
                        return False
        return True

    def place_shape(self, shape, x, y, color):
        for i in range(len(shape)):
            for j in range(len(shape[0])):
                if shape[i][j]:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])

    def draw(self, screen, offset_x):
        for i in range(self.height):
            for j in range(self.width):
                color = COLORS[self.grid[i][j]]
                pygame.draw.rect(screen, color,
                                 (offset_x + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(screen, COLORS[7],
                                 (offset_x + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1) # White outline

class Piece:
    def __init__(self, shape=None, x=0, y=0, color=0):
        if shape is None:
            self.shape = random.choice(SHAPES)
        else:
            self.shape = shape
        self.x = x
        self.y = y
        self.color = color if color else random.randint(1, len(COLORS) - 2) # Avoid black and white

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

class Player:
    def __init__(self, player_id, grid_width, grid_height, offset_x):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.current_piece = Piece(x=grid_width // 2 - 2, y=0)
        self.next_piece = Piece()
        self.offset_x = offset_x
        self.game_over = False
        self.lines_cleared = 0
        self.contribution = 0

    def update(self):
        if not self.game_over:
            if self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y + 1):
                self.current_piece.y += 1
            else:
                self.grid.place_shape(self.current_piece.shape, self.current_piece.x, self.current_piece.y, self.current_piece.color)
                lines_cleared = self.grid.clear_lines()
                self.lines_cleared += lines_cleared
                self.score += lines_cleared ** 2 * 100  # Example scoring
                self.current_piece = self.next_piece
                self.current_piece.x = self.grid.width // 2 - 2
                self.current_piece.y = 0
                self.next_piece = Piece()
                if self.grid.is_game_over():
                    self.game_over = True

    def move_left(self):
        if self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x - 1, self.current_piece.y):
            self.current_piece.x -= 1

    def move_right(self):
        if self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x + 1, self.current_piece.y):
            self.current_piece.x += 1

    def rotate(self):
        original_shape = [list(row) for row in [list(r) for r in self.current_piece.shape]] #Deep copy
        self.current_piece.rotate()
        if not self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y):
            self.current_piece.shape = original_shape # Revert if invalid

    def drop(self):
        while self.grid.is_valid_move(self.current_piece.shape, self.current_piece.x, self.current_piece.y + 1):
            self.current_piece.y += 1
        self.update()

    def draw(self, screen):
        self.grid.draw(screen, self.offset_x)

        # Draw current piece
        for i in range(len(self.current_piece.shape)):
            for j in range(len(self.current_piece.shape[0])):
                if self.current_piece.shape[i][j]:
                    pygame.draw.rect(screen, COLORS[self.current_piece.color],
                                     (self.offset_x + (self.current_piece.x + j) * CELL_SIZE,
                                      (self.current_piece.y + i) * CELL_SIZE,
                                      CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, COLORS[7],
                                     (self.offset_x + (self.current_piece.x + j) * CELL_SIZE,
                                      (self.current_piece.y + i) * CELL_SIZE,
                                      CELL_SIZE, CELL_SIZE), 1)

        # Draw next piece preview (small)
        for i in range(len(self.next_piece.shape)):
            for j in range(len(self.next_piece.shape[0])):
                if self.next_piece.shape[i][j]:
                    pygame.draw.rect(screen, COLORS[self.next_piece.color],
                                     (self.offset_x + (self.grid.width + 1 + j) * CELL_SIZE,
                                      (2 + i) * CELL_SIZE,
                                      CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, COLORS[7],
                                     (self.offset_x + (self.grid.width + 1 + j) * CELL_SIZE,
                                      (2 + i) * CELL_SIZE,
                                      CELL_SIZE, CELL_SIZE), 1)

        # Display score
        font = pygame.font.Font(None, 30)
        score_text = font.render(f"Score: {self.score}", True, COLORS[7])
        screen.blit(score_text, (self.offset_x, SCREEN_HEIGHT - 30))

        # Display next piece label
        next_text = font.render("Next:", True, COLORS[7])
        screen.blit(next_text, (self.offset_x + self.grid.width * CELL_SIZE, CELL_SIZE))

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player(1, GRID_WIDTH, GRID_HEIGHT, 0),
            Player(2, GRID_WIDTH, GRID_HEIGHT, GRID_WIDTH * CELL_SIZE),
            Player(3, GRID_WIDTH, GRID_HEIGHT, 2 * GRID_WIDTH * CELL_SIZE)
        ]
        self.running = True
        self.game_over = False
        self.frame_count = 0

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    self.players[0].move_left()
                if event.key == pygame.K_d:
                    self.players[0].move_right()
                if event.key == pygame.K_w:
                    self.players[0].rotate()
                if event.key == pygame.K_s:
                    self.players[0].drop()

                if event.key == pygame.K_j:
                    self.players[1].move_left()
                if event.key == pygame.K_l:
                    self.players[1].move_right()
                if event.key == pygame.K_i:
                    self.players[1].rotate()
                if event.key == pygame.K_k:
                    self.players[1].drop()

                if event.key == pygame.K_LEFT:
                    self.players[2].move_left()
                if event.key == pygame.K_RIGHT:
                    self.players[2].move_right()
                if event.key == pygame.K_UP:
                    self.players[2].rotate()
                if event.key == pygame.K_DOWN:
                    self.players[2].drop()

    def update(self):
        if not self.game_over:
            self.frame_count += 1
            if self.frame_count % (FPS // 2) == 0: #Adjust speed
                for player in self.players:
                    player.update()

            if all(player.game_over for player in self.players):
                self.game_over = True
                self.calculate_contributions()

    def calculate_contributions(self):
        total_lines_cleared = sum(player.lines_cleared for player in self.players)
        if total_lines_cleared == 0:
            for player in self.players:
                player.contribution = 1 / len(self.players)
        else:
            for player in self.players:
                player.contribution = player.lines_cleared / total_lines_cleared

    def draw(self):
        self.screen.fill(COLORS[0])  # Black background
        for player in self.players:
            player.draw(self.screen)

        if self.game_over:
            font = pygame.font.Font(None, 50)
            game_over_text = font.render("Game Over!", True, COLORS[1])
            text_rect = game_over_text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2 - 50))
            self.screen.blit(game_over_text, text_rect)

            # Display contributions
            y_offset = SCREEN_HEIGHT // 2
            for i, player in enumerate(self.players):
                contribution_text = font.render(f"Player {player.player_id}: {player.contribution:.2f}", True, COLORS[7])
                text_rect = contribution_text.get_rect(center=(SCREEN_WIDTH // 2, y_offset + i * 40))
                self.screen.blit(contribution_text, text_rect)

        pygame.display.flip()

    def run(self):
        while self.running:
            self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

