            for player in self.players:
                player.move_down()
        else:
            self.game_over = True
            self.calculate_contributions()

    def calculate_contributions(self):
        total_lines_cleared = sum(player.lines_cleared for player in self.players)
        self.overall_score = sum(player.score for player in self.players)

        if total_lines_cleared > 0:
            for i, player in enumerate(self.players):
                self.player_contributions[i] = (player.lines_cleared / total_lines_cleared) * self.overall_score
        else:
            self.player_contributions = [0] * self.num_players

