        [[1, 1], [1, 1]],  # O
        [[0, 1, 1], [1, 1, 0]],  # Z
        [[1, 1, 0], [0, 1, 1]],  # S
        [[1, 0, 0], [1, 1, 1]],  # L
        [[0, 0, 1], [1, 1, 1]],  # J
        [[0, 1, 0], [1, 1, 1]]   # T
