import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE * 3 + 20  # Space for 3 grids and some padding
HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)
COLORS = [RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA]

class Piece:
    SHAPES = [
        [[1, 1, 1, 1]],  # I
        [[1, 1], [1, 1]],  # O
        [[0, 1, 1], [1, 1, 0]],  # Z
        [[1, 1, 0], [0, 1, 1]],  # S
        [[1, 0, 0], [1, 1, 1]],  # L
        [[0, 0, 1], [1, 1, 1]],  # J
        [[0, 1, 0], [1, 1, 1]]   # T
    ]

    def __init__(self, x, y, shape=None):
        self.x = x
        self.y = y
        if shape is None:
            self.shape = random.choice(self.SHAPES)
        else:
            self.shape = shape
        self.color = random.choice(COLORS)

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = [list(row) for row in rotated_shape]

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, piece, x, y):
        for i in range(piece.get_height()):
            for j in range(piece.get_width()):
                if piece.shape[i][j]:
                    grid_x = x + j
                    grid_y = y + i
                    if grid_x < 0 or grid_x >= self.width or grid_y >= self.height or (grid_y >= 0 and self.grid[grid_y][grid_x] != 0):
                        return False
        return True

    def place_piece(self, piece, x, y):
        for i in range(piece.get_height()):
            for j in range(piece.get_width()):
                if piece.shape[i][j]:
                    self.grid[y + i][x + j] = piece.color

    def clear_lines(self):
        lines_cleared = 0
        full_rows = []
        for i in range(self.height):
            if all(self.grid[i]):
                full_rows.append(i)

        for row in full_rows:
            del self.grid[row]
            self.grid.insert(0, [0] * self.width)
            lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])

    def draw(self, screen, x_offset):
        for i in range(self.height):
            for j in range(self.width):
                if self.grid[i][j]:
                    pygame.draw.rect(screen, self.grid[i][j], (x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, GRAY, (x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)
                else:
                    pygame.draw.rect(screen, BLACK, (x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(screen, GRAY, (x_offset + j * CELL_SIZE, i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

class Player:
    def __init__(self, player_id, grid_width, grid_height):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.current_piece = None
        self.piece_x = grid_width // 2 - 2
        self.piece_y = 0
        self.next_piece = Piece(0, 0)
        self.game_over = False
        self.lines_cleared = 0

    def new_piece(self):
        self.current_piece = self.next_piece
        self.piece_x = self.grid.width // 2 - self.current_piece.get_width() // 2
        self.piece_y = 0
        self.next_piece = Piece(0, 0)
        if not self.grid.is_valid_move(self.current_piece, self.piece_x, self.piece_y):
            self.game_over = True

    def move_left(self):
        if not self.game_over and self.grid.is_valid_move(self.current_piece, self.piece_x - 1, self.piece_y):
            self.piece_x -= 1

    def move_right(self):
        if not self.game_over and self.grid.is_valid_move(self.current_piece, self.piece_x + 1, self.piece_y):
            self.piece_x += 1

    def move_down(self):
        if not self.game_over:
            if self.grid.is_valid_move(self.current_piece, self.piece_x, self.piece_y + 1):
                self.piece_y += 1
            else:
                self.grid.place_piece(self.current_piece, self.piece_x, self.piece_y)
                lines_cleared = self.grid.clear_lines()
                self.lines_cleared += lines_cleared
                if lines_cleared == 1:
                    self.score += 100
                elif lines_cleared == 2:
                    self.score += 300
                elif lines_cleared == 3:
                    self.score += 500
                elif lines_cleared >= 4:
                    self.score += 800
                self.new_piece()

    def rotate(self):
        if not self.game_over:
            original_shape = [row[:] for row in self.current_piece.shape]
            self.current_piece.rotate()
            if not self.grid.is_valid_move(self.current_piece, self.piece_x, self.piece_y):
                self.current_piece.shape = original_shape

    def draw(self, screen, x_offset):
        self.grid.draw(screen, x_offset)
        if self.current_piece:
            for i in range(self.current_piece.get_height()):
                for j in range(self.current_piece.get_width()):
                    if self.current_piece.shape[i][j]:
                        pygame.draw.rect(screen, self.current_piece.color, (x_offset + (self.piece_x + j) * CELL_SIZE, (self.piece_y + i) * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                        pygame.draw.rect(screen, GRAY, (x_offset + (self.piece_x + j) * CELL_SIZE, (self.piece_y + i) * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

class TetrisGame:
    def __init__(self, num_players=3):
        pygame.init()
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        pygame.display.set_caption("Three Player Tetris")
        self.clock = pygame.time.Clock()
        self.num_players = num_players
        self.players = [Player(i, GRID_WIDTH, GRID_HEIGHT) for i in range(num_players)]
        for player in self.players:
            player.new_piece()
        self.game_over = False
        self.font = pygame.font.Font(None, 36)
        self.overall_score = 0
        self.player_contributions = [0] * num_players

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    self.players[0].move_left()
                if event.key == pygame.K_d:
                    self.players[0].move_right()
                if event.key == pygame.K_s:
                    self.players[0].move_down()
                if event.key == pygame.K_w:
                    self.players[0].rotate()

                if event.key == pygame.K_j:
                    self.players[1].move_left()
                if event.key == pygame.K_l:
                    self.players[1].move_right()
                if event.key == pygame.K_k:
                    self.players[1].move_down()
                if event.key == pygame.K_i:
                    self.players[1].rotate()

                if event.key == pygame.K_LEFT:
                    self.players[2].move_left()
                if event.key == pygame.K_RIGHT:
                    self.players[2].move_right()
                if event.key == pygame.K_DOWN:
                    self.players[2].move_down()
                if event.key == pygame.K_UP:
                    self.players[2].rotate()

    def update(self):
        if not any(player.game_over for player in self.players):
            for player in self.players:
                player.move_down()
        else:
            self.game_over = True
            self.calculate_contributions()

    def calculate_contributions(self):
        total_lines_cleared = sum(player.lines_cleared for player in self.players)
        self.overall_score = sum(player.score for player in self.players)

        if total_lines_cleared > 0:
            for i, player in enumerate(self.players):
                self.player_contributions[i] = (player.lines_cleared / total_lines_cleared) * self.overall_score
        else:
            self.player_contributions = [0] * self.num_players

    def draw(self):
        self.screen.fill(BLACK)
        for i, player in enumerate(self.players):
            x_offset = i * (GRID_WIDTH * CELL_SIZE) + i * 10  # Add some spacing between grids
            player.draw(self.screen, x_offset)
            score_text = self.font.render(f"Player {i+1}: {player.score}", True, WHITE)
            self.screen.blit(score_text, (x_offset, HEIGHT - 30))

        if self.game_over:
            game_over_text = self.font.render("Game Over!", True, RED)
            self.screen.blit(game_over_text, (WIDTH // 2 - 80, HEIGHT // 2 - 18))

            overall_score_text = self.font.render(f"Overall Score: {self.overall_score}", True, WHITE)
            self.screen.blit(overall_score_text, (WIDTH // 2 - 120, HEIGHT // 2 + 18))

            for i, contribution in enumerate(self.player_contributions):
                contribution_text = self.font.render(f"Player {i+1} Contribution: {contribution:.2f}", True, WHITE)
                self.screen.blit(contribution_text, (10, 50 + i * 30))

        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)

