import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE * 3 + 20  # Space for 3 grids and some padding
HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [(0, 255, 255), (0, 0, 255), (255, 127, 0), (255, 255, 0),
          (0, 255, 0), (255, 0, 0), (128, 0, 128)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 1, 0]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        for i in range(len(self.shape[0])):
            new_row = []
            for j in range(len(self.shape) - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j]:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            if x < 0 or x >= self.width or y >= self.height or (y >= 0 and self.grid[y][x] != 0):
                return False
        return True

    def place_tetromino(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def is_game_over(self):
        return any(self.grid[0])

class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.current_tetromino = None
        self.grid_x_offset = grid_x_offset
        self.drop_speed = 1
        self.drop_counter = 0
        self.game_over = False

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[SHAPES.index(shape)]
        self.current_tetromino = Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)
        if not self.grid.is_valid_move(self.current_tetromino):
            self.game_over = True

    def move_tetromino(self, dx):
        if self.game_over:
            return
        self.current_tetromino.x += dx
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.x -= dx

    def drop_tetromino(self):
        if self.game_over:
            return
        self.current_tetromino.y += 1
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.y -= 1
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.score += lines_cleared ** 2 * 100
            self.create_tetromino()

    def rotate_tetromino(self):
        if self.game_over:
            return
        original_shape = self.current_tetromino.shape
        self.current_tetromino.rotate()
        if not self.grid.is_valid_move(self.current_tetromino):
            self.current_tetromino.shape = original_shape

    def update(self):
        if self.game_over:
            return
        self.drop_counter += self.drop_speed
        if self.drop_counter >= FPS:
            self.drop_tetromino()
            self.drop_counter = 0

    def draw(self, screen):
        # Draw grid
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                color = BLACK if self.grid.grid[y][x] == 0 else self.grid.grid[y][x]
                pygame.draw.rect(screen, color,
                                 (self.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(screen, GRAY,
                                 (self.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

        # Draw tetromino
        if self.current_tetromino:
            for x, y in self.current_tetromino.get_cells():
                pygame.draw.rect(screen, self.current_tetromino.color,
                                 (self.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(screen, GRAY,
                                 (self.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

        # Draw score
        font = pygame.font.Font(None, 36)
        text = font.render(f"Player {self.player_id + 1} Score: {self.score}", True, WHITE)
        screen.blit(text, (self.grid_x_offset, HEIGHT))

        if self.game_over:
            game_over_font = pygame.font.Font(None, 72)
            game_over_text = game_over_font.render("Game Over", True, WHITE)
            text_rect = game_over_text.get_rect(center=(self.grid_x_offset + GRID_WIDTH * CELL_SIZE // 2, HEIGHT // 2))
            screen.blit(game_over_text, text_rect)

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT + 50))
    pygame.display.set_caption("Three Player Tetris")
    clock = pygame.time.Clock()

    players = [
        Player(0, 0),
        Player(1, GRID_WIDTH * CELL_SIZE + 10),
        Player(2, 2 * (GRID_WIDTH * CELL_SIZE) + 20)
    ]

    for player in players:
        player.create_tetromino()

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    players[0].move_tetromino(-1)
                if event.key == pygame.K_RIGHT:
                    players[0].move_tetromino(1)
                if event.key == pygame.K_DOWN:
                    players[0].drop_tetromino()
                if event.key == pygame.K_UP:
                    players[0].rotate_tetromino()

                if event.key == pygame.K_a:
                    players[1].move_tetromino(-1)
                if event.key == pygame.K_d:
                    players[1].move_tetromino(1)
                if event.key == pygame.K_s:
                    players[1].drop_tetromino()
                if event.key == pygame.K_w:
                    players[1].rotate_tetromino()

                if event.key == pygame.K_j:
                    players[2].move_tetromino(-1)
                if event.key == pygame.K_l:
                    players[2].move_tetromino(1)
                if event.key == pygame.K_k:
                    players[2].drop_tetromino()
                if event.key == pygame.K_i:
                    players[2].rotate_tetromino()

        # Update
        for player in players:
            player.update()

        # Draw
        screen.fill(BLACK)
        for player in players:
            player.draw(screen)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()

if __name__ == "__main__":
    main()

