        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.grid_x_offset = grid_x_offset

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[SHAPES.index(shape)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(
            self.current_tetromino,
            self.current_tetromino.get_x(),
            self.current_tetromino.get_y(),
        ):
            return False  # Game over
        return True

    def move_left(self):
        if self.current_tetromino:
            new_x = self.current_tetromino.get_x() - 1
            if self.grid.is_valid_move(
                self.current_tetromino, new_x, self.current_tetromino.get_y()
            ):
                self.current_tetromino.set_x(new_x)

    def move_right(self):
        if self.current_tetromino:
            new_x = self.current_tetromino.get_x() + 1
            if self.grid.is_valid_move(
                self.current_tetromino, new_x, self.current_tetromino.get_y()
            ):
                self.current_tetromino.set_x(new_x)

    def move_down(self):
        if self.current_tetromino:
            new_y = self.current_tetromino.get_y() + 1
            if self.grid.is_valid_move(
                self.current_tetromino, self.current_tetromino.get_x(), new_y
            ):
                self.current_tetromino.set_y(new_y)
                return True
            else:
                self.lock_tetromino()
                return False
        return False

    def rotate_tetromino(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.get_shape()
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(
                self.current_tetromino,
                self.current_tetromino.get_x(),
                self.current_tetromino.get_y(),
            ):
                self.current_tetromino.shape = original_shape  # Revert rotation

    def lock_tetromino(self):
        self.grid.place_tetromino(self.current_tetromino)
        lines_cleared = self.grid.clear_lines()
        self.score += lines_cleared**2 * 100  # Example scoring
        self.current_tetromino = None

    def get_score(self):
        return self.score

    def get_grid(self):
        return self.grid.get_grid()

    def get_next_tetromino(self):
        return self.next_tetromino

    def reset(self):
        self.score = 0
        self.grid.reset()
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()


class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Three Player Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player(1, 0),
            Player(2, GRID_WIDTH * BLOCK_SIZE + 30),
            Player(3, 2 * GRID_WIDTH * BLOCK_SIZE + 60),
        ]
        self.game_over = False
        self.font = pygame.font.Font(None, 36)

    def draw_grid(self, grid, x_offset):
        for i, row in enumerate(grid):
            for j, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(
                        self.screen,
                        cell,
                        (
                            x_offset + j * BLOCK_SIZE,
                            i * BLOCK_SIZE,
                            BLOCK_SIZE,
                            BLOCK_SIZE,
                        ),
                    )
                    pygame.draw.rect(
                        self.screen,
                        BLACK,
                        (
                            x_offset + j * BLOCK_SIZE,
                            i * BLOCK_SIZE,
                            BLOCK_SIZE,
                            BLOCK_SIZE,
                        ),
                        1,
                    )
                else:
                    pygame.draw.rect(
                        self.screen,
                        GRAY,
                        (
                            x_offset + j * BLOCK_SIZE,
                            i * BLOCK_SIZE,
                            BLOCK_SIZE,
                            BLOCK_SIZE,
                        ),
                        1,
                    )

    def draw_tetromino(self, tetromino, x_offset):
        if tetromino:
            shape = tetromino.get_shape()
            color = tetromino.get_color()
            x = tetromino.get_x()
            y = tetromino.get_y()
            for i, row in enumerate(shape):
                for j, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(
                            self.screen,
                            color,
                            (
                                x_offset + (x + j) * BLOCK_SIZE,
                                (y + i) * BLOCK_SIZE,
                                BLOCK_SIZE,
                                BLOCK_SIZE,
                            ),
                        )
                        pygame.draw.rect(
                            self.screen,
                            BLACK,
                            (
                                x_offset + (x + j) * BLOCK_SIZE,
                                (y + i) * BLOCK_SIZE,
                                BLOCK_SIZE,
                                BLOCK_SIZE,
                            ),
                            1,
                        )

    def draw_next_tetromino(self, tetromino, x_offset, y_offset):
        shape = tetromino.get_shape()
        color = tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(
                        self.screen,
                        color,
                        (
                            x_offset + j * BLOCK_SIZE,
                            y_offset + i * BLOCK_SIZE,
                            BLOCK_SIZE,
                            BLOCK_SIZE,
                        ),
                    )
                    pygame.draw.rect(
                        self.screen,
                        BLACK,
                        (
                            x_offset + j * BLOCK_SIZE,
                            y_offset + i * BLOCK_SIZE,
                            BLOCK_SIZE,
                            BLOCK_SIZE,
                        ),
                        1,
                    )

    def draw_scores(self):
        for player in self.players:
            score_text = self.font.render(
                f"Player {player.player_id}: {player.get_score()}", True, WHITE
            )
            self.screen.blit(
                score_text,
                (
                    player.grid_x_offset,
                    SCREEN_HEIGHT - 40,
                ),
            )

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:
                    self.players[0].move_left()
                if event.key == pygame.K_d:
                    self.players[0].move_right()
                if event.key == pygame.K_s:
                    self.players[0].move_down()
                if event.key == pygame.K_w:
                    self.players[0].rotate_tetromino()

                if event.key == pygame.K_j:
                    self.players[1].move_left()
                if event.key == pygame.K_l:
                    self.players[1].move_right()
                if event.key == pygame.K_k:
                    self.players[1].move_down()
                if event.key == pygame.K_i:
                    self.players[1].rotate_tetromino()

                if event.key == pygame.K_LEFT:
                    self.players[2].move_left()
                if event.key == pygame.K_RIGHT:
                    self.players[2].move_right()
                if event.key == pygame.K_DOWN:
                    self.players[2].move_down()
                if event.key == pygame.K_UP:
                    self.players[2].rotate_tetromino()

    def update(self):
        for player in self.players:
            if player.current_tetromino is None:
                if not player.spawn_tetromino():
                    self.game_over = True
                    return

            if not player.move_down():
                pass  # Lock tetromino is handled in move_down

    def draw(self):
        self.screen.fill(BLACK)
        for player in self.players:
            self.draw_grid(player.get_grid(), player.grid_x_offset)
            self.draw_tetromino(
                player.current_tetromino, player.grid_x_offset
            )
            self.draw_next_tetromino(
                player.get_next_tetromino(), player.grid_x_offset, SCREEN_HEIGHT // 2
            )
        self.draw_scores()
        pygame.display.flip()

    def run(self):
        while not self.game_over:
            self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(FPS)

        print("Game Over!")
        winner = max(self.players, key=lambda player: player.get_score())
        print(f"Player {winner.player_id} wins with a score of {winner.get_score()}!")

        # Reset the game
        for player in self.players:
            player.reset()
        self.game_over = False
        self.run()  # Restart the game

if __name__ == "__main__":
    game = Game()
    game.run()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE * 3 + 200  # Space for 3 grids + scoreboards
HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30

# Colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)

COLORS = [GRAY, RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]],  # T
]


class Tetromino:
    def __init__(self, x, y, shape_index):
        self.x = x
        self.y = y
        self.shape = SHAPES[shape_index]
        self.color = COLORS[shape_index + 1]  # +1 to avoid gray
        self.rotation = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i, row in enumerate(self.shape):
            for j, cell in enumerate(row):
                if cell:
                    cells.append((self.x + j, self.y + i))
        return cells

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)


class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_position(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            if x < 0 or x >= self.width or y >= self.height or self.grid[y][x] != 0:
                return False
        if any(y < 0 for _, y in cells):
            return True # Allow piece to be partially above the grid
        return True

    def place_tetromino(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen, offset_x):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x]:
                    pygame.draw.rect(
                        screen,
                        self.grid[y][x],
                        (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                    )
                    pygame.draw.rect(
                        screen,
                        BLACK,
                        (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                        1,
                    )
                else:
                    pygame.draw.rect(
                        screen,
                        GRAY,
                        (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                        1,
                    )


class Player:
    def __init__(self, player_id, grid_width, grid_height):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.game_over = False

    def create_tetromino(self):
        shape_index = random.randint(0, len(SHAPES) - 1)
        return Tetromino(self.grid.width // 2 - 2, 0, shape_index)

    def new_tetromino(self):
        self.tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.tetromino.x = self.grid.width // 2 - 2
        self.tetromino.y = 0
        if not self.grid.is_valid_position(self.tetromino):
            self.game_over = True

    def move_left(self):
        if self.tetromino:
            self.tetromino.x -= 1
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.x += 1

    def move_right(self):
        if self.tetromino:
            self.tetromino.x += 1
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.x -= 1

    def move_down(self):
        if self.tetromino:
            self.tetromino.y += 1
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.y -= 1
                self.lock_tetromino()
                return False
            return True
        return False

    def rotate_tetromino(self):
        if self.tetromino:
            original_shape = self.tetromino.shape
            self.tetromino.rotate()
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.shape = original_shape  # Revert rotation

    def lock_tetromino(self):
        self.grid.place_tetromino(self.tetromino)
        lines_cleared = self.grid.clear_lines()
        self.score += self.calculate_score(lines_cleared)
        self.new_tetromino()

    def calculate_score(self, lines_cleared):
        if lines_cleared == 1:
            return 40
        elif lines_cleared == 2:
            return 100
        elif lines_cleared == 3:
            return 300
        elif lines_cleared == 4:
            return 1200
        return 0

    def draw_tetromino(self, screen, offset_x):
        if self.tetromino:
            cells = self.tetromino.get_cells()
            for x, y in cells:
                pygame.draw.rect(
                    screen,
                    self.tetromino.color,
                    (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                )
                pygame.draw.rect(
                    screen,
                    BLACK,
                    (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                    1,
                )

    def draw_next_tetromino(self, screen, offset_x, offset_y):
        if self.next_tetromino:
            for i, row in enumerate(self.next_tetromino.shape):
                for j, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(
                            screen,
                            self.next_tetromino.color,
                            (offset_x + j * CELL_SIZE, offset_y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                        )
                        pygame.draw.rect(
                            screen,
                            BLACK,
                            (offset_x + j * CELL_SIZE, offset_y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                            1,
                        )


def draw_score(screen, player, offset_x, offset_y):
    font = pygame.font.Font(None, 36)
    text = font.render(f"Player {player.player_id + 1} Score: {player.score}", True, WHITE)
    screen.blit(text, (offset_x, offset_y))

def draw_game_over(screen, player, offset_x, offset_y):
    font = pygame.font.Font(None, 72)
    text = font.render(f"Player {player.player_id + 1} GAME OVER", True, RED)
    text_rect = text.get_rect(center=(offset_x, offset_y))
    screen.blit(text, text_rect)

def main():
    pygame.init()
    screen = pygame.display.set_mode((WIDTH, HEIGHT))
    pygame.display.set_caption("Three Player Tetris")

    players = [Player(i, GRID_WIDTH, GRID_HEIGHT) for i in range(3)]
    for player in players:
        player.new_tetromino()

    clock = pygame.time.Clock()
    drop_speed = 1  # Blocks per second
    drop_interval = 1 / drop_speed * 1000  # Milliseconds
    last_drop_time = pygame.time.get_ticks()

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_a:  # Player 1 left
                    players[0].move_left()
                if event.key == pygame.K_d:  # Player 1 right
                    players[0].move_right()
                if event.key == pygame.K_s:  # Player 1 down
                    players[0].move_down()
                if event.key == pygame.K_q:  # Player 1 rotate
                    players[0].rotate_tetromino()

                if event.key == pygame.K_j:  # Player 2 left
                    players[1].move_left()
                if event.key == pygame.K_l:  # Player 2 right
                    players[1].move_right()
                if event.key == pygame.K_k:  # Player 2 down
                    players[1].move_down()
                if event.key == pygame.K_u:  # Player 2 rotate
                    players[1].rotate_tetromino()

                if event.key == pygame.K_LEFT:  # Player 3 left
                    players[2].move_left()
                if event.key == pygame.K_RIGHT:  # Player 3 right
                    players[2].move_right()
                if event.key == pygame.K_DOWN:  # Player 3 down
                    players[2].move_down()
                if event.key == pygame.K_UP:  # Player 3 rotate
                    players[2].rotate_tetromino()

        # Game Logic
        current_time = pygame.time.get_ticks()
        for player in players:
            if not player.game_over:
                if current_time - last_drop_time > drop_interval:
                    if not player.move_down():
                        pass # Lock tetromino is handled in move_down
                    last_drop_time = current_time

        # Drawing
        screen.fill(BLACK)

        # Draw grids and tetrominos for each player
        grid_offset_x = 0
        for i, player in enumerate(players):
            player.grid.draw(screen, grid_offset_x)
            player.draw_tetromino(screen, grid_offset_x)
            draw_score(screen, player, grid_offset_x, HEIGHT - 50)
            player.draw_next_tetromino(screen, grid_offset_x + GRID_WIDTH * CELL_SIZE + 10, 50)
            if player.game_over:
                draw_game_over(screen, player, grid_offset_x + GRID_WIDTH * CELL_SIZE // 2, HEIGHT // 2)
            grid_offset_x += GRID_WIDTH * CELL_SIZE

            if i < 2:
                grid_offset_x += 50 # Add space between grids

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()


if __name__ == "__main__":
    main()

import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
BLOCK_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * BLOCK_SIZE * 3 + 60  # Space for 3 grids + gaps
SCREEN_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30

# Colors
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [
    (0, 255, 255),  # Cyan
    (0, 0, 255),  # Blue
    (255, 127, 0),  # Orange
    (255, 255, 0),  # Yellow
    (0, 255, 0),  # Green
    (255, 0, 0),  # Red
    (128, 0, 128),  # Purple
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
]


class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        for i in range(len(self.shape[0])):
            new_row = []
            for j in range(len(self.shape) - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color

    def get_x(self):
        return self.x

    def get_y(self):
        return self.y

    def set_x(self, x):
        self.x = x

    def set_y(self, y):
        self.y = y


class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino, x, y):
        shape = tetromino.get_shape()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    grid_x = x + j
                    grid_y = y + i
                    if (
                        grid_x < 0
                        or grid_x >= self.width
                        or grid_y >= self.height
                        or self.grid[grid_y][grid_x] != 0
                    ):
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        color = tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def get_grid(self):
        return self.grid

    def reset(self):
        self.grid = [[0] * self.width for _ in range(self.height)]


class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.score = 0
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.grid_x_offset = grid_x_offset

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[SHAPES.index(shape)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(
            self.current_tetromino,
            self.current_tetromino.get_x(),
            self.current_tetromino.get_y(),
        ):
            return False  # Game over
        return True

    def move_left(self):
        if self.current_tetromino:
            new_x = self.current_tetromino.get_x() - 1
            if self.grid.is_valid_move(
                self.current_tetromino, new_x, self.current_tetromino.get_y()
            ):
                self.current_tetromino.set_x(new_x)

    def move_right(self):
        if self.current_tetromino:
            new_x = self.current_tetromino.get_x() + 1
            if self.grid.is_valid_move(
                self.current_tetromino, new_x, self.current_tetromino.get_y()
            ):
                self.current_tetromino.set_x(new_x)

    def move_down(self):
        if self.current_tetromino:
            new_y = self.current_tetromino.get_y() + 1
            if self.grid.is_valid_move(
                self.current_tetromino, self.current_tetromino.get_x(), new_y
            ):
                self.current_tetromino.set_y(new_y)
                return True
            else:
                self.lock_tetromino()
                return False
        return False

    def rotate_tetromino(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.get_shape()
