SCREEN_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
FPS = 30

# Colors
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [
    (0, 255, 255),  # Cyan
    (0, 0, 255),  # Blue
    (255, 127, 0),  # Orange
    (255, 255, 0),  # Yellow
    (0, 255, 0),  # Green
    (255, 0, 0),  # Red
    (128, 0, 128),  # Purple
]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 0, 0], [1, 1, 1]],  # J
    [[0, 0, 1], [1, 1, 1]],  # L
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 1], [1, 1]],  # O
    [[0, 1, 0], [1, 1, 1]],  # T
]


class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        for i in range(len(self.shape[0])):
            new_row = []
            for j in range(len(self.shape) - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_shape(self):
        return self.shape

    def get_color(self):
        return self.color

    def get_x(self):
        return self.x

    def get_y(self):
        return self.y

    def set_x(self, x):
        self.x = x

    def set_y(self, y):
        self.y = y


class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino, x, y):
        shape = tetromino.get_shape()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    grid_x = x + j
                    grid_y = y + i
                    if (
                        grid_x < 0
                        or grid_x >= self.width
                        or grid_y >= self.height
                        or self.grid[grid_y][grid_x] != 0
                    ):
                        return False
        return True

    def place_tetromino(self, tetromino):
        shape = tetromino.get_shape()
        x = tetromino.get_x()
        y = tetromino.get_y()
        color = tetromino.get_color()
        for i, row in enumerate(shape):
            for j, cell in enumerate(row):
                if cell:
                    self.grid[y + i][x + j] = color

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.height):
            if all(self.grid[i]):
                del self.grid[i]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def get_grid(self):
        return self.grid

    def reset(self):
        self.grid = [[0] * self.width for _ in range(self.height)]


class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.score = 0
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.grid_x_offset = grid_x_offset

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[SHAPES.index(shape)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(
            self.current_tetromino,
            self.current_tetromino.get_x(),
            self.current_tetromino.get_y(),
        ):
            return False  # Game over
        return True

    def move_left(self):
        if self.current_tetromino:
            new_x = self.current_tetromino.get_x() - 1
            if self.grid.is_valid_move(
                self.current_tetromino, new_x, self.current_tetromino.get_y()
            ):
                self.current_tetromino.set_x(new_x)

    def move_right(self):
        if self.current_tetromino:
            new_x = self.current_tetromino.get_x() + 1
            if self.grid.is_valid_move(
                self.current_tetromino, new_x, self.current_tetromino.get_y()
            ):
                self.current_tetromino.set_x(new_x)

    def move_down(self):
        if self.current_tetromino:
            new_y = self.current_tetromino.get_y() + 1
            if self.grid.is_valid_move(
                self.current_tetromino, self.current_tetromino.get_x(), new_y
            ):
                self.current_tetromino.set_y(new_y)
                return True
            else:
                self.lock_tetromino()
                return False
        return False

    def rotate_tetromino(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.get_shape()
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(
                self.current_tetromino,
                self.current_tetromino.get_x(),
                self.current_tetromino.get_y(),
            ):
                self.current_tetromino.shape = original_shape  # Revert rotation

    def lock_tetromino(self):
        self.grid.place_tetromino(self.current_tetromino)
        lines_cleared = self.grid.clear_lines()
        self.score += lines_cleared**2 * 100  # Example scoring
        self.current_tetromino = None

    def get_score(self):
        return self.score

    def get_grid(self):
        return self.grid.get_grid()

    def get_next_tetromino(self):
        return self.next_tetromino

    def reset(self):
        self.score = 0
        self.grid.reset()
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()


