import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
WIDTH = GRID_WIDTH * CELL_SIZE * 3 + 200  # Space for 3 grids + scoreboards
HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30

# Colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)
YELLOW = (255, 255, 0)
CYAN = (0, 255, 255)
MAGENTA = (255, 0, 255)

COLORS = [GRAY, RED, GREEN, BLUE, YELLOW, CYAN, MAGENTA]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # S
    [[1, 1, 0], [0, 1, 1]],  # Z
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]],  # T
]


class Tetromino:
    def __init__(self, x, y, shape_index):
        self.x = x
        self.y = y
        self.shape = SHAPES[shape_index]
        self.color = COLORS[shape_index + 1]  # +1 to avoid gray
        self.rotation = 0

    def rotate(self):
        rotated_shape = list(zip(*self.shape[::-1]))
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i, row in enumerate(self.shape):
            for j, cell in enumerate(row):
                if cell:
                    cells.append((self.x + j, self.y + i))
        return cells

    def get_width(self):
        return len(self.shape[0])

    def get_height(self):
        return len(self.shape)


class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_position(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            if x < 0 or x >= self.width or y >= self.height or self.grid[y][x] != 0:
                return False
        if any(y < 0 for _, y in cells):
            return True # Allow piece to be partially above the grid
        return True

    def place_tetromino(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen, offset_x):
        for y in range(self.height):
            for x in range(self.width):
                if self.grid[y][x]:
                    pygame.draw.rect(
                        screen,
                        self.grid[y][x],
                        (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                    )
                    pygame.draw.rect(
                        screen,
                        BLACK,
                        (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                        1,
                    )
                else:
                    pygame.draw.rect(
                        screen,
                        GRAY,
                        (offset_x + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE),
                        1,
                    )


class Player:
    def __init__(self, player_id, grid_width, grid_height):
        self.player_id = player_id
        self.grid = Grid(grid_width, grid_height)
        self.score = 0
        self.tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.game_over = False

    def create_tetromino(self):
        shape_index = random.randint(0, len(SHAPES) - 1)
        return Tetromino(self.grid.width // 2 - 2, 0, shape_index)

    def new_tetromino(self):
        self.tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.tetromino.x = self.grid.width // 2 - 2
        self.tetromino.y = 0
        if not self.grid.is_valid_position(self.tetromino):
            self.game_over = True

    def move_left(self):
        if self.tetromino:
            self.tetromino.x -= 1
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.x += 1

    def move_right(self):
        if self.tetromino:
            self.tetromino.x += 1
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.x -= 1

    def move_down(self):
        if self.tetromino:
            self.tetromino.y += 1
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.y -= 1
                self.lock_tetromino()
                return False
            return True
        return False

    def rotate_tetromino(self):
        if self.tetromino:
            original_shape = self.tetromino.shape
            self.tetromino.rotate()
            if not self.grid.is_valid_position(self.tetromino):
                self.tetromino.shape = original_shape  # Revert rotation

    def lock_tetromino(self):
        self.grid.place_tetromino(self.tetromino)
        lines_cleared = self.grid.clear_lines()
        self.score += self.calculate_score(lines_cleared)
        self.new_tetromino()

    def calculate_score(self, lines_cleared):
        if lines_cleared == 1:
            return 40
