            text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
            self.screen.blit(text, text_rect)

        pygame.display.flip()

    def render_grid(self, player):
        for y in range(player.grid.height):
            for x in range(player.grid.width):
                color = player.grid.grid[y][x]
                if color:
                    pygame.draw.rect(self.screen, color, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
