import pygame
import random

# Constants
GRID_WIDTH = 10
GRID_HEIGHT = 20
CELL_SIZE = 30
SCREEN_WIDTH = GRID_WIDTH * CELL_SIZE * 3  # Triple width for 3 players
SCREEN_HEIGHT = GRID_HEIGHT * CELL_SIZE
FPS = 30
WHITE = (255, 255, 255)
BLACK = (0, 0, 0)
GRAY = (128, 128, 128)
COLORS = [(0, 255, 255), (0, 0, 255), (255, 127, 0), (255, 255, 0), (0, 255, 0), (255, 0, 0), (128, 0, 128)]

# Tetromino shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[0, 1, 1], [1, 1, 0]],  # Z
    [[1, 1, 0], [0, 1, 1]],  # S
    [[1, 0, 0], [1, 1, 1]],  # L
    [[0, 0, 1], [1, 1, 1]],  # J
    [[0, 1, 0], [1, 1, 1]]   # T
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        rotated_shape = []
        rows = len(self.shape)
        cols = len(self.shape[0])
        for i in range(cols):
            new_row = []
            for j in range(rows - 1, -1, -1):
                new_row.append(self.shape[j][i])
            rotated_shape.append(new_row)
        self.shape = rotated_shape

    def get_cells(self):
        cells = []
        for i in range(len(self.shape)):
            for j in range(len(self.shape[0])):
                if self.shape[i][j] == 1:
                    cells.append((self.x + j, self.y + i))
        return cells

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        for x, y in tetromino.get_cells():
            if x < 0 or x >= self.width or y >= self.height:
                return False
            if y >= 0 and self.grid[y][x] != 0:
                return False
        return True

    def place_tetromino(self, tetromino):
        for x, y in tetromino.get_cells():
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.grid_x_offset = grid_x_offset

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[SHAPES.index(shape)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def spawn_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = self.create_tetromino()
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        if not self.grid.is_valid_move(self.current_tetromino):
            return False  # Game over
        return True

    def move_tetromino(self, dx, dy):
        if self.current_tetromino:
            self.current_tetromino.x += dx
            self.current_tetromino.y += dy
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= dx
                self.current_tetromino.y -= dy
                return False
        return True

    def rotate_tetromino(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape # Revert rotation

    def drop_tetromino(self):
        if self.current_tetromino:
            while self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y += 1
            self.current_tetromino.y -= 1
            self.grid.place_tetromino(self.current_tetromino)
            lines_cleared = self.grid.clear_lines()
            self.score += self.calculate_score(lines_cleared)
            self.current_tetromino = None
            return True
        return False

    def calculate_score(self, lines_cleared):
        if lines_cleared == 1:
            return 100
        elif lines_cleared == 2:
            return 300
        elif lines_cleared == 3:
            return 500
        elif lines_cleared == 4:
            return 800
        return 0

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player(1, 0),
            Player(2, GRID_WIDTH * CELL_SIZE),
            Player(3, GRID_WIDTH * CELL_SIZE * 2)
        ]
        self.game_over = False
        self.fall_speed = 500 # milliseconds
        self.last_fall_time = pygame.time.get_ticks()

    def handle_input(self, event):
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_LEFT:
                self.players[0].move_tetromino(-1, 0)
            elif event.key == pygame.K_RIGHT:
                self.players[0].move_tetromino(1, 0)
            elif event.key == pygame.K_DOWN:
                self.players[0].move_tetromino(0, 1)
            elif event.key == pygame.K_UP:
                self.players[0].rotate_tetromino()
            elif event.key == pygame.K_SPACE:
                self.players[0].drop_tetromino()

            if event.key == pygame.K_a:
                self.players[1].move_tetromino(-1, 0)
            elif event.key == pygame.K_d:
                self.players[1].move_tetromino(1, 0)
            elif event.key == pygame.K_s:
                self.players[1].move_tetromino(0, 1)
            elif event.key == pygame.K_w:
                self.players[1].rotate_tetromino()
            elif event.key == pygame.K_q:
                self.players[1].drop_tetromino()

            if event.key == pygame.K_j:
                self.players[2].move_tetromino(-1, 0)
            elif event.key == pygame.K_l:
                self.players[2].move_tetromino(1, 0)
            elif event.key == pygame.K_k:
                self.players[2].move_tetromino(0, 1)
            elif event.key == pygame.K_i:
                self.players[2].rotate_tetromino()
            elif event.key == pygame.K_u:
                self.players[2].drop_tetromino()

    def update(self):
        current_time = pygame.time.get_ticks()
        for player in self.players:
            if player.current_tetromino is None:
                if not player.spawn_tetromino():
                    self.game_over = True
                    return

            if current_time - self.last_fall_time > self.fall_speed:
                if not player.move_tetromino(0, 1):
                    player.grid.place_tetromino(player.current_tetromino)
                    player.score += player.calculate_score(player.grid.clear_lines())
                    player.current_tetromino = None
                self.last_fall_time = current_time

    def render(self):
        self.screen.fill(BLACK)
        for player in self.players:
            self.render_grid(player)
            self.render_next_tetromino(player)
            self.render_score(player)

        if self.game_over:
            font = pygame.font.Font(None, 50)
            text = font.render("Game Over!", True, WHITE)
            text_rect = text.get_rect(center=(SCREEN_WIDTH // 2, SCREEN_HEIGHT // 2))
            self.screen.blit(text, text_rect)

        pygame.display.flip()

    def render_grid(self, player):
        for y in range(player.grid.height):
            for x in range(player.grid.width):
                color = player.grid.grid[y][x]
                if color:
                    pygame.draw.rect(self.screen, color, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(self.screen, GRAY, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)
                else:
                    pygame.draw.rect(self.screen, BLACK, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                    pygame.draw.rect(self.screen, GRAY, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

        if player.current_tetromino:
            for x, y in player.current_tetromino.get_cells():
                pygame.draw.rect(self.screen, player.current_tetromino.color, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                pygame.draw.rect(self.screen, GRAY, (player.grid_x_offset + x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def render_next_tetromino(self, player):
        font = pygame.font.Font(None, 24)
        text = font.render(f"Next:", True, WHITE)
        self.screen.blit(text, (player.grid_x_offset, SCREEN_HEIGHT - 100))

        if player.next_tetromino:
            next_x = player.grid_x_offset
            next_y = SCREEN_HEIGHT - 70
            for i in range(len(player.next_tetromino.shape)):
                for j in range(len(player.next_tetromino.shape[0])):
                    if player.next_tetromino.shape[i][j] == 1:
                        pygame.draw.rect(self.screen, player.next_tetromino.color, (next_x + j * CELL_SIZE, next_y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE))
                        pygame.draw.rect(self.screen, GRAY, (next_x + j * CELL_SIZE, next_y + i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def render_score(self, player):
         font = pygame.font.Font(None, 36)
         text = font.render(f"Player {player.player_id}: {player.score}", True, WHITE)
         self.screen.blit(text, (player.grid_x_offset, 20))

    def run(self):
        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False
                self.handle_input(event)

            if not self.game_over:
                self.update()
            self.render()
            self.clock.tick(FPS)

        pygame.quit()

if __name__ == "__main__":
