        self.width = width
        self.height = height
        self.grid = [[0] * width for _ in range(height)]

    def is_valid_move(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            if x < 0 or x >= self.width or y >= self.height or self.grid[y][x] != 0:
                return False
        if y < 0:
            return True
        return True

    def place_tetromino(self, tetromino):
        cells = tetromino.get_cells()
        for x, y in cells:
            self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

class Player:
    def __init__(self, player_id, grid_x_offset):
        self.player_id = player_id
        self.grid = Grid(GRID_WIDTH, GRID_HEIGHT)
        self.score = 0
        self.current_tetromino = None
        self.next_tetromino = self.create_tetromino()
        self.grid_x_offset = grid_x_offset

    def create_tetromino(self):
        shape = random.choice(SHAPES)
        color = COLORS[random.randint(1, len(COLORS) - 1)]
        return Tetromino(GRID_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.current_tetromino.x = GRID_WIDTH // 2 - len(self.current_tetromino.shape[0]) // 2
        self.current_tetromino.y = 0
        self.next_tetromino = self.create_tetromino()
        if not self.grid.is_valid_move(self.current_tetromino):
            return False #Game Over
        return True

    def move_tetromino_down(self):
        if self.current_tetromino:
            self.current_tetromino.y += 1
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.y -= 1
                self.grid.place_tetromino(self.current_tetromino)
                lines_cleared = self.grid.clear_lines()
                self.score += lines_cleared ** 2 * 100
                if not self.new_tetromino():
                    return False #Game Over
        return True

    def move_tetromino_sideways(self, direction):
        if self.current_tetromino:
            self.current_tetromino.x += direction
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.x -= direction

    def rotate_tetromino(self):
        if self.current_tetromino:
            original_shape = self.current_tetromino.shape
            self.current_tetromino.rotate()
            if not self.grid.is_valid_move(self.current_tetromino):
                self.current_tetromino.shape = original_shape # Revert rotation

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player(1, 0),
            Player(2, GRID_WIDTH * CELL_SIZE),
            Player(3, GRID_WIDTH * CELL_SIZE * 2)
        ]
        self.game_over = [False, False, False]
        self.font = pygame.font.Font(None, 36)

        for player in self.players:
            player.new_tetromino()

    def handle_input(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.players[0].move_tetromino_sideways(-1)
                elif event.key == pygame.K_RIGHT:
                    self.players[0].move_tetromino_sideways(1)
                elif event.key == pygame.K_DOWN:
                    self.players[0].move_tetromino_down()
                elif event.key == pygame.K_UP:
                    self.players[0].rotate_tetromino()

                if event.key == pygame.K_a:
                    self.players[1].move_tetromino_sideways(-1)
                elif event.key == pygame.K_d:
                    self.players[1].move_tetromino_sideways(1)
                elif event.key == pygame.K_s:
                    self.players[1].move_tetromino_down()
                elif event.key == pygame.K_w:
                    self.players[1].rotate_tetromino()

                if event.key == pygame.K_j:
                    self.players[2].move_tetromino_sideways(-1)
                elif event.key == pygame.K_l:
                    self.players[2].move_tetromino_sideways(1)
                elif event.key == pygame.K_k:
                    self.players[2].move_tetromino_down()
                elif event.key == pygame.K_i:
                    self.players[2].rotate_tetromino()

    def update(self):
        for i, player in enumerate(self.players):
            if not self.game_over[i]:
                if not player.move_tetromino_down():
                    self.game_over[i] = True

    def render(self):
        self.screen.fill((0, 0, 0))

        for player in self.players:
            self.draw_grid(player)
            self.draw_tetromino(player.current_tetromino, player.grid_x_offset)
            self.draw_next_tetromino(player)
            self.draw_score(player)

        pygame.display.flip()

    def draw_grid(self, player):
        for y in range(player.grid.height):
            for x in range(player.grid.width):
                color = COLORS[player.grid.grid[y][x]]
                pygame.draw.rect(self.screen, color,
                                 (x * CELL_SIZE + player.grid_x_offset, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                pygame.draw.rect(self.screen, (50, 50, 50),
                                 (x * CELL_SIZE + player.grid_x_offset, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_tetromino(self, tetromino, x_offset):
        if tetromino:
            for x, y in tetromino.get_cells():
                pygame.draw.rect(self.screen, tetromino.color,
                                 (x * CELL_SIZE + x_offset, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                pygame.draw.rect(self.screen, (50, 50, 50),
                                 (x * CELL_SIZE + x_offset, y * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_next_tetromino(self, player):
        next_tetromino = player.next_tetromino
        x_offset = player.grid_x_offset + GRID_WIDTH * CELL_SIZE + 20
        y_offset = 50
        for i in range(len(next_tetromino.shape)):
            for j in range(len(next_tetromino.shape[0])):
                if next_tetromino.shape[i][j] == 1:
                    pygame.draw.rect(self.screen, next_tetromino.color,
                                     (x_offset + j * CELL_SIZE, y_offset + i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 0)
                    pygame.draw.rect(self.screen, (50, 50, 50),
                                     (x_offset + j * CELL_SIZE, y_offset + i * CELL_SIZE, CELL_SIZE, CELL_SIZE), 1)

    def draw_score(self, player):
        text = self.font.render(f"Player {player.player_id} Score: {player.score}", True, (255, 255, 255))
        self.screen.blit(text, (player.grid_x_offset, SCREEN_HEIGHT - 50))

    def run(self):
        self.running = True
        while self.running:
            self.handle_input()
            self.update()
            self.render()
            self.clock.tick(FPS)

            if all(self.game_over):
                print("Game Over!")
                self.running = False

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()
